const refCounts = new Map<string, number>();
const fsUnsubscribers = new Map<string, () => void>();

export async function acquireModel(input): Promise<{model, phase, errorCode?}> {
  const uri = `file://${input.filePath}`;
  const count = (refCounts.get(uri) ?? 0) + 1;
  refCounts.set(uri, count);
  if (count === 1) {
    const result = await readFileForModel(input);
    if (result.isBinary) return {model: null, phase: "binary"};
    if (result.error) return {model: null, phase: "error", errorCode};
    const model = monaco.editor.createModel(result.content, langFromExt, Uri.parse(uri));
    notifyDidOpen(uri, input.workspaceId, langId, result.content);
    model.onDidChangeContent(() => notifyDidChange(uri, model.getValue())); // debounced
    fsUnsubscribers.set(uri, subscribeFsChanged(input, ({content, isBinary}) => {
      if (!isBinary && model.getValue() === lastSavedValue) model.setValue(content); // clean only
    }));
  }
  return {model: monaco.editor.getModel(Uri.parse(uri)), phase: "ready"};
}

export function releaseModel(input): void {
  const uri = `file://${input.filePath}`;
  const count = (refCounts.get(uri) ?? 0) - 1;
  if (count <= 0) {
    refCounts.delete(uri);
    fsUnsubscribers.get(uri)?.();
    fsUnsubscribers.delete(uri);
    notifyDidClose(uri);
    monaco.editor.getModel(Uri.parse(uri))?.dispose();
  } else {
    refCounts.set(uri, count);
  }
}

export function useSharedModel(input): {model, phase, errorCode?} {
  // useState + useEffect로 acquire/release. cleanup에서 release.
}
```

