const ackCounters = new Map<string, number>();

export async function spawnSession({tabId, cwd, cols, rows}): Promise<void> {
  await ipcCall("pty", "spawn", {tabId, cwd, cols, rows});
}
export function writeInput(tabId, data): void { ipcCall("pty","write",{tabId,data}); }
export function resizeSession(tabId, cols, rows): void { ipcCall("pty","resize",...); }
export function killSession(tabId): void {
  ackCounters.delete(tabId);
  ipcCall("pty","kill",{tabId}).catch(()=>{}); // fire-and-forget
}
export function subscribeData(tabId, onChunk): () => void {
  return ipcListen("pty","data", (msg) => {
    if (msg.tabId !== tabId) return;
    onChunk(msg.data);
    const count = (ackCounters.get(tabId) ?? 0) + msg.data.length;
    if (count >= FLOW_CONTROL.ACK_SIZE) {
      ipcCall("pty","ack",{tabId, bytes: count});
      ackCounters.set(tabId, 0);
    } else {
      ackCounters.set(tabId, count);
    }
  });
}
export function subscribeExit(tabId, onExit): () => void { ... }
```

