export interface TerminalController { dispose(): void; }
export async function createTerminalController({tabId, cwd, container}): Promise<TerminalController> {
  await fonts.load(...);
  const term = new Terminal({...});
  const fit = new FitAddon();
  term.loadAddon(fit);
  // WebGL fallback Canvas
  term.open(container);
  fit.fit();
  await spawnSession({tabId, cwd, cols: term.cols, rows: term.rows});
  const unsubData = subscribeData(tabId, chunk => term.write(chunk));
  const unsubExit = subscribeExit(tabId, () => term.write("\\r\\n[Process exited]"));
  term.onData(d => writeInput(tabId, d));
  const ro = new ResizeObserver(debounced(() => { fit.fit(); resizeSession(tabId, term.cols, term.rows); }));
  ro.observe(container);
  return {
    dispose() {
      unsubData(); unsubExit(); ro.disconnect(); term.dispose();
      // pty kill은 호출 안 함 — close 신호에서만
    }
  };
}
```

